import time
from dataclasses import dataclass

from starlette.responses import JSONResponse
from starlette.types import ASGIApp, Message, Receive, Scope, Send


@dataclass
class _TokenBucket:
    tokens: float
    last_refill: float


class RateLimitMiddleware:
    def __init__(
        self,
        app: ASGIApp,
        requests_per_minute: int = 60,
        burst_size: int = 10,
    ) -> None:
        self.app = app
        self.requests_per_minute = requests_per_minute
        self.burst_size = burst_size
        self._refill_rate: float = requests_per_minute / 60.0  # tokens per second
        self._buckets: dict[str, _TokenBucket] = {}

    def _consume_token(self, client_ip: str) -> tuple[bool, float, float]:
        """Try to consume a token from the bucket for the given client IP.

        Returns:
            A tuple of (allowed, remaining_tokens, retry_after_seconds).
        """
        now = time.monotonic()
        bucket = self._buckets.get(client_ip)

        if bucket is None:
            bucket = _TokenBucket(
                tokens=self.burst_size - 1,
                last_refill=now,
            )
            self._buckets[client_ip] = bucket
            return (True, bucket.tokens, 0.0)

        # Refill tokens based on elapsed time
        elapsed = now - bucket.last_refill
        bucket.tokens = min(
            self.burst_size, bucket.tokens + elapsed * self._refill_rate
        )
        bucket.last_refill = now

        if bucket.tokens >= 1.0:
            bucket.tokens -= 1.0
            return (True, bucket.tokens, 0.0)

        # Not enough tokens — calculate wait time
        deficit = 1.0 - bucket.tokens
        retry_after = deficit / self._refill_rate
        return (False, 0.0, retry_after)

    async def __call__(self, scope: Scope, receive: Receive, send: Send) -> None:
        if scope["type"] != "http":
            await self.app(scope, receive, send)
            return

        client = scope.get("client")
        client_ip = client[0] if client else "127.0.0.1"

        allowed, remaining, retry_after = self._consume_token(client_ip)

        if not allowed:
            reset_time = int(time.time() + retry_after)
            response = JSONResponse(
                status_code=429,
                content={
                    "detail": "Rate limit exceeded",
                    "retry_after": round(retry_after, 2),
                },
                headers={
                    "X-RateLimit-Limit": str(self.requests_per_minute),
                    "X-RateLimit-Remaining": "0",
                    "X-RateLimit-Reset": str(reset_time),
                },
            )
            await response(scope, receive, send)
            return

        # Allowed — wrap send to inject rate limit headers into the response
        reset_time = int(time.time() + 60)

        async def send_with_headers(message: Message) -> None:
            if message["type"] == "http.response.start":
                headers = list(message.get("headers", []))
                headers.append(
                    (
                        b"x-ratelimit-limit",
                        str(self.requests_per_minute).encode(),
                    )
                )
                headers.append(
                    (b"x-ratelimit-remaining", str(int(remaining)).encode())
                )
                headers.append(
                    (b"x-ratelimit-reset", str(reset_time).encode())
                )
                message = {**message, "headers": headers}
            await send(message)

        await self.app(scope, receive, send_with_headers)

