"""Demo application showing RateLimitMiddleware usage."""

from fastapi import FastAPI
from fastapi.middleware.rate_limit import RateLimitMiddleware

app = FastAPI()

app.add_middleware(
    RateLimitMiddleware,
    requests_per_minute=60,
    burst_size=5,
)


@app.get("/")
async def root():
    return {"message": "hello"}


@app.get("/other")
async def other():
    return {"message": "other"}

